CREATE DEFINER=`root`@`localhost` PROCEDURE `sp_tb_senhas_count_by_date`(
    IN p_data_refeicao VARCHAR(10)
)
BEGIN
    SELECT COUNT(*) AS total
    FROM tb_senhas
    WHERE data_refeicao = p_data_refeicao;
END ;;
DELIMITER ;
